let data;
try {
  data = $json.value ? JSON.parse($json.value) : null;
} catch (e) {
  data = null;
}

let modelIndex;
let shouldSet = false;

if (data && typeof data.modelIndex === 'number') {
  // Alternate: flip the previous modelIndex
  modelIndex = data.modelIndex === 0 ? 1 : 0;
  shouldSet = true; // store the new one
} else {
  // If no data, default to model 0 and store it
  modelIndex = 0;
  shouldSet = true;
}

return [
  {
    json: {
      modelIndex,
      shouldSet
    }
  }
];

